item.content:encoded:
div#main-content {
    padding-top: 72px;
}
body, h1, h2, h3, h4, h5, h6, p {
	font-family:"Raleway";
}
.et_pb_section:not(.et_pb_with_background) h1 {
	margin-bottom:1em;
}
h2, h3, h4, h5 {
    margin-bottom: 1.3em;
	padding-bottom:0;
}
.et_pb_section:not(.et_pb_with_background):not(.et_pb_section_0_tb_header) .et_pb_text_inner ul:last-of-type,
.et_pb_section:not(.et_pb_with_background):not(.et_pb_section_0_tb_header) .et_pb_text_inner p:last-of-type,
.et_pb_section:not(.et_pb_with_background):not(.et_pb_section_0_tb_header) .et_pb_text_inner ul:only-of-type,
.et_pb_section:not(.et_pb_with_background):not(.et_pb_section_0_tb_header) .et_pb_text_inner p:only-of-type {
    margin-bottom: 1.5em;
}

.et_pb_section:not(.et_pb_with_background):not(.et_pb_section_0_tb_header) h1 {
	color: #222;
}
.et_pb_section:not(.et_pb_with_background):not(.et_pb_section_0_tb_header) h2:not(.top) {
    color: #BF9C5F;
	margin-top:1em;
	text-shadow: 1px 1px #eee;
}
.et_pb_section:not(.et_pb_with_background):not(.et_pb_section_0_tb_header) h4 {
	margin-top:1em;
}

.call-now-button:not(.cnb-domain-pro).cnb-full.cnb-items-1:after {
	display:none;
}

/* ToC */

div#ez-toc-container {
    background: #f7f7f7 !important;
	border:1px solid #e4e4e4 !important;
	color:#888 !important;
}
span.ez-toc-js-icon-con {
    background: white;
}
div#ez-toc-container .ez-toc-title {
    font-size: unset;
    vertical-align: -webkit-baseline-middle;
}

@media (min-width:979px){
	.call-now-button, .cnb-full.cnb-fixed.cnb-full-bottom.cnb-items-1.call-now-button.cnb-domain-starter {
		display:none;
	}
} 

@media (min-width:450px) {
.call-now-button.cnb-full.cnb-items-1:after {
	display:none !important;
}
}

