.nav li ul, .et_pb_menu .et-menu-nav>ul ul {
  padding:10px 0;
  width:260px;
}
.et-menu li li {
  padding:0 10px;
  width:100%;
}
.et-menu li li a {
  width:100%;
}
ul#mobile_menu1 {
  left:auto;
  right:0;
  width:200px;
}
@media screen and (max-width:980px){
.et_pb_section_0_tb_header .et_pb_column.et_pb_column_2_3 {
  width: 20% !important;

	}
.et_pb_section_0_tb_header  .et_pb_column.et_pb_column_1_3 {
   margin-bottom:0;
    width: 78% !important;
	}
    .et_pb_row_0 .et_pb_column_0 {
     background-position:left bottom 23%; 
  }
  .et_pb_row_0 {
    background-position: right 0px top -5% !important;
  }
}
@media screen and (max-wdith:800px){
    .et_pb_row_0 {
    background-position: right 0px top -5% !important;
  }
}
@media screen and (max-width:787px){
.et_pb_section_0_tb_header .et_pb_column.et_pb_column_2_3 {
  width: 20% !important;
	}
