   margin-bottom:0;
    width: 78% !important;
	}
}
@media screen and (max-width:479px){
.et_pb_section_0_tb_header .et_pb_column.et_pb_column_2_3 {
  margin-bottom:0;
  width: 20% !important;
	}
.et_pb_section_0_tb_header  .et_pb_column.et_pb_column_1_3 {
    width: 78% !important;
	}
}

